// ADR-005: Error Handler IoT con preservacion de payload (dead-letter)
// REG-003: workflow de error configurado en settings.errorWorkflow del orquestador
const ctx = $input.item.json;

const run_id = ctx.workflow?.runId || ctx.execution?.id || 'unknown';
const node_name = ctx.execution?.lastNodeExecuted || 'unknown';
const error_message = ctx.error?.message || 'Error desconocido';

// Intentar recuperar el payload original del webhook para dead-letter
const payload_original = ctx.data?.resultData?.runData?.['webhook-sensor']?.[0]?.data?.main?.[0]?.[0]?.json?.body || null;

const log = {
  run_id,
  etapa: 'ERROR_HANDLER',
  status: 'error',
  workflow_name: ctx.workflow?.name || 'iot-to-be-orquestador',
  node_name,
  error_message,
  error_type: error_message.includes('connection') ? 'integration' : 'logic',
  payload_original_disponible: payload_original !== null,
  ts: new Date().toISOString()
};

console.log(JSON.stringify(log));

return [{ json: { ...log, payload_original, run_id, node_name, error_message } }];
